// Build a premium HTML email from the latest scored opportunities.
// Runs once per incoming item (expects /pipeline/score output shape).

const raw = Array.isArray($json.relevant_consultations) ? $json.relevant_consultations : [];

const dedupeByKey = (arr) => {
  const byId = new Map();
  for (const o of (Array.isArray(arr) ? arr : [])) {
    const key = String((o && (o.reference || o.id)) || "").trim();
    if (!key) continue;
    if (!byId.has(key)) byId.set(key, o);
  }
  return Array.from(byId.values());
};
const items = dedupeByKey(raw);

const esc = (s) => String(s ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');
const escAttr = (s) => esc(s).replace(/\"/g, '&quot;');

const fmtMoney = (n) => {
  const v = Number(n);
  if (!Number.isFinite(v) || v <= 0) return 'N/A';
  const s = v.toFixed(2);
  const parts = s.split('.');
  const t = parts[0];
  let out = '';
  for (let i = t.length; i > 0; i -= 3) {
    const start = Math.max(0, i - 3);
    out = t.slice(start, i) + (out ? ' ' + out : '');
  }
  return out + ',' + parts[1] + ' DH';
};

const parseDeadlineDate = (value) => {
  if (!value) return null;
  if (value instanceof Date) return Number.isNaN(value.getTime()) ? null : value;
  const v = String(value).trim();
  if (!v) return null;
  const fr = v.match(/^(\d{2})\/(\d{2})\/(\d{4})(?:\s+(\d{2}):(\d{2}))?$/);
  if (fr) {
    const [, dd, mm, yyyy, hh = "00", min = "00"] = fr;
    const d = new Date(Number(yyyy), Number(mm) - 1, Number(dd), Number(hh), Number(min));
    return Number.isNaN(d.getTime()) ? null : d;
  }
  if (/^\d{4}-\d{2}-\d{2}/.test(v)) {
    const d = new Date(v);
    return Number.isNaN(d.getTime()) ? null : d;
  }
  const d = new Date(v);
  return Number.isNaN(d.getTime()) ? null : d;
};

const toDeadlineComparableDate = (value) => {
  const v = value == null ? "" : String(value).trim();
  const d = parseDeadlineDate(value);
  if (!d) return null;
  const isDateOnly =
    /^(\d{2})\/(\d{2})\/(\d{4})$/.test(v) ||
    /^\d{4}-\d{2}-\d{2}$/.test(v) ||
    /^\d{4}-\d{2}-\d{2}T00:00(?::00(?:\.\d{1,3})?)?(?:Z)?$/.test(v);
  if (!isDateOnly) return d;
  return new Date(d.getFullYear(), d.getMonth(), d.getDate(), 23, 59, 59, 999);
};

const fmtDate = (d) => {
  const dt = (d instanceof Date) ? d : parseDeadlineDate(d);
  if (!dt || Number.isNaN(dt.getTime())) return "N/A";
  const dd = String(dt.getDate()).padStart(2, "0");
  const mm = String(dt.getMonth() + 1).padStart(2, "0");
  return dd + "/" + mm + "/" + dt.getFullYear();
};

const badgeHtml = (lvl) => {
  const L = String(lvl || '').toUpperCase();
  const label = (L === 'HOT' || L === 'WARM' || L === 'COLD') ? L : 'COLD';
  const bg = (label === 'HOT') ? '#b42318' : (label === 'WARM') ? '#f97316' : '#6b7280';
  return '<span style="display:inline-block;padding:3px 10px;border-radius:999px;font-weight:700;font-size:11px;line-height:14px;color:#fff;background:' + bg + ';">' + esc(label) + '</span>';
};

// Casablanca time string (works even if container is in UTC)
